def hanoi(n: Int) -> Int:
    if n <= 0:
        return 0
    return 2 * hanoi(n - 1) + 1

def transpose(m: List[List[Float64]]) -> List[List[Float64]]:
    var rows = len(m)
    var cols = len(m[0])
    var result = List[List[Float64]]()
    for j in range(cols):
        var row = List[Float64]()
        for i in range(rows):
            row.append(m[i][j])
        result.append(row^)
    return result^

def upper_tri_sum(m: List[List[Float64]]) -> Float64:
    var n = len(m)
    var s: Float64 = 0.0
    for i in range(n):
        for j in range(i, n):
            s += m[i][j]
    return s

@fieldwise_init
struct Vec2(Copyable, Movable):
    var x: Float64
    var y: Float64

def add(a: Vec2, b: Vec2) -> Vec2:
    return Vec2(a.x + b.x, a.y + b.y)

def weekday_from_daynum(d: Int) -> Int:
    var r = d % 7
    if r == 0:
        return 6
    return r - 1

from std.math import pow

def wind_chill(tc: Float64, v: Float64) -> Float64:
    var vp = pow(v, 0.16)
    return 13.12 + 0.6215 * tc - 11.37 * vp + 0.3965 * tc * vp

def wrap_to_range(x: Float64, lo: Float64, hi: Float64) -> Float64:
    var range = hi - lo
    var r = x - lo - Float64(floor((x - lo) / range)) * range
    if r < 0.0:
        r += range
    return lo + r
